const jobs = $input.first().json.jobs || [];

// 🔹 role keywords (Python / Automation roles)
const roleKeywords = [
  "python",
  "automation",
  "rpa",
  "developer",
  "backend",
  "software",
  "engineer"
];

// 🔹 India location keywords
const indiaLocations = [
  "india",
  "remote (india)",
  "bangalore",
  "bengaluru",
  "kerala",
  "kochi",
  "trivandrum",
  "hyderabad",
  "chennai",
  "pune",
  "mumbai",
  "delhi"
];

// 🔹 fresher / junior indicators
const juniorKeywords = [
  "junior",
  "intern",
  "trainee",
  "entry",
  "associate",
  "graduate"
];

const filtered = jobs
  .filter(job => {
    const title = (job.title || "").toLowerCase();
    const location = (job.candidate_required_location || "").toLowerCase();
    const description = (job.description || "").toLowerCase();

    // match role
    const isRoleMatch = roleKeywords.some(k => title.includes(k));

    // match India
    const isIndia = indiaLocations.some(loc => location.includes(loc));

    // entry level logic (RELAXED for freshers)
    const isEntryLevel =
      juniorKeywords.some(k => title.includes(k)) ||
      juniorKeywords.some(k => description.includes(k)) ||
      description.includes("0-2") ||
      description.includes("1 year") ||
      !description.includes("years"); // allow if no experience mentioned

    return isRoleMatch && isIndia && isEntryLevel;
  })
  .map(job => ({
    json: {
      title: job.title,
      company: job.company_name,
      location: job.candidate_required_location,
      url: job.url
    }
  }));

// 🔹 If no jobs found, send default message
if (filtered.length === 0) {
  return [
    {
      json: {
        title: "No fresher Python/Automation jobs found today 😔",
        company: "",
        location: "India",
        url: ""
      }
    }
  ];
}

return filtered;
